INSERT INTO formations (id_formation, titre, description, duree, prix, categorie, date_debut, places_disponibles, created_at, updated_at, deleted_at, benefices, id_pays) SELECT gen_random_uuid(), v.* FROM (VALUES ('Nouveaux enjeux de la fonction secrétaire/assistant', 'Formation sur l’évolution du rôle de secrétaire/assistant(e) vers un soutien stratégique.', 5, 100000.00, 'entreprise', '2026-07-15', 30, '2026-01-14 12:37:32', '2026-02-18 23:44:04', NULL, E'--- OBJECTIFS ---\n• Compréhension des évolutions récentes de la fonction secrétaire/assistant(e)\n• Acquisition de nouvelles compétences stratégiques et organisationnelles\n• Optimisation de la gestion administrative et des priorités\n• Amélioration de la communication et de la coordination avec les managers\n• Utilisation des outils numériques pour accroître la performance\n• Développement de l’autonomie, de la proactivité et du leadership\n\n--- OBJECTIFS DÉTAILLÉS ---\nComprendre les évolutions récentes de la fonction secrétaire et assistant(e), maîtriser les nouvelles compétences et responsabilités attendues, optimiser la gestion administrative et organisationnelle, améliorer la communication et le support aux managers, et utiliser les outils numériques pour gagner en efficacité.\n\n--- PRÉREQUIS ---\nExpérience préalable en secrétariat ou assistanat souhaitée. Connaissances de base en bureautique (Word, Excel, PowerPoint).\n\n--- CONTENU ---\nModule 1 : La fonction Secrétaire et Assistant(e) aujourd’hui\nModule 2 : Gestion administrative et organisationnelle\nModule 3 : Communication et coordination efficace\nModule 4 : Support stratégique et gestion de projets\nModule 5 : Digitalisation et outils modernes\nModule 6 : Développement personnel et compétences transversales\nModule 7 : Performance et évaluation\n\n--- NIVEAU ---\nTous niveaux\n\n--- PUBLIC ---\nAssistant(e)s de direction, secrétaires, adjoints administratifs, toute personne en charge du soutien administratif et organisationnel dans une entreprise.\n\n--- MÉTHODES ---\nPrésentations interactives, ateliers pratiques, simulations réalistes, études de cas, jeux de rôle, évaluations formatives avec feedback personnalisé.\n\n--- SUPPORTS ---\nOutils bureautiques (Word, Excel, PowerPoint), logiciels collaboratifs (Google Workspace, Microsoft 365), outils de gestion documentaire, supports PDF et modèles pratiques.\n\n--- CERTIFICATION ---\nAttestation de participation remise par ISD Groupe', 'ba52f30c-c061-41b8-b0f7-afa6eca6fa76')) AS v(titre, description, duree, prix, categorie, date_debut, places_disponibles, created_at, updated_at, deleted_at, benefices, id_pays) WHERE NOT EXISTS (SELECT 1 FROM formations f WHERE f.titre = v.titre AND f.date_debut = v.date_debut::date);
